const App: React.FC = () => {
  const [selectedUniversityId, setSelectedUniversityId] = useState<string>(universityPresets[0].id);

  const activePreset = universityPresets.find(p => p.id === selectedUniversityId) || universityPresets[0];

  const [receiptData, setReceiptData] = useState<ReceiptData>(activePreset.createInitialData());
  const [universityInfo, setUniversityInfo] = useState<UniversityInfo>(activePreset.info);
  const [isVerifying, setIsVerifying] = useState(false);
  const [verificationResult, setVerificationResult] = useState<VerificationResult | null>(null);
  const [verificationError, setVerificationError] = useState<string | null>(null);

  const receiptRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const admissionYearNum = parseInt(receiptData.admissionYear, 10);
    if (!isNaN(admissionYearNum) && String(admissionYearNum).length === 4) {
        // Most Israeli programs are 3 years, others are 4. Preset logic handles initial load.
        // We'll respect the preset's logic if the user changes the year manually.
        const duration = selectedUniversityId === 'biu' ? 3 : 4;
        const newGradYear = String(admissionYearNum + duration);
        if (newGradYear !== receiptData.graduationYear) {
            setReceiptData(prev => ({ ...prev, graduationYear: newGradYear }));
        }
    }
  }, [receiptData.admissionYear, selectedUniversityId]);

  const handleUniversityChange = (id: string) => {
    const newPreset = universityPresets.find(p => p.id === id);
    if (newPreset) {
        setSelectedUniversityId(id);
        setUniversityInfo(newPreset.info);
        setReceiptData(newPreset.createInitialData());
        setVerificationResult(null);
        setVerificationError(null);
    }
  };

  const handleDownload = async (format: 'png' | 'pdf') => {
    if (!receiptRef.current) return;

    window.scrollTo(0, 0);

    const canvas = await html2canvas(receiptRef.current, {
      scale: 2,
      useCORS: true,
      backgroundColor: '#ffffff',
    });

    const cleanedStudentId = receiptData.studentId.replace(/[^a-zA-Z0-9]/g, '_');
    const firstName = receiptData.studentName.split(' ')[0]?.toLowerCase() || 'student';
    const filename = `receipt_${cleanedStudentId}_${firstName}.${format}`;

    if (format === 'png') {
      const dataUrl = canvas.toDataURL('image/png');
      const link = document.createElement('a');
      link.href = dataUrl;
      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } else {
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit: 'px',
        format: [canvas.width, canvas.height],
      });
      pdf.addImage(imgData, 'PNG', 0, 0, canvas.width, canvas.height);
      pdf.save(filename);
    }
  };

  const handleGenerateSample = () => {
    setReceiptData(activePreset.createRandomData());
    setVerificationResult(null);
    setVerificationError(null);
  };

  const handleVerify = async () => {
    if (!receiptRef.current) return;

    setIsVerifying(true);
    setVerificationResult(null);
    setVerificationError(null);
    window.scrollTo(0, 0);

    try {
        const canvas = await html2canvas(receiptRef.current, {
            scale: 2,
            useCORS: true,
            backgroundColor: '#ffffff',
        });
        const dataUrl = canvas.toDataURL('image/jpeg');
        const base64Data = dataUrl.split(',')[1];

        const result = await verifyReceipt(base64Data);
        setVerificationResult(result);

    } catch (error) {
        console.error("Verification failed:", error);
        setVerificationError("Sorry, the AI verification failed. Please try again.");
    } finally {
        setIsVerifying(false);
    }
  };


  return (
    <div className="min-h-screen bg-gray-900 text-gray-200 flex flex-col items-center py-10 px-4">
      <div className="w-full max-w-7xl mx-auto">
        <header className="text-center mb-10">
          <h1 className="text-4xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-indigo-600">
            Tuition Fee Receipt Generator
          </h1>
          <p className="text-gray-400 mt-2">
            Select a university and customize the details to generate a new tuition fee receipt.
          </p>
        </header>

        <main className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="bg-gray-800 p-6 rounded-lg shadow-lg border border-gray-700">
            <ReceiptForm 
                receiptData={receiptData}
                setReceiptData={setReceiptData}
                universityInfo={universityInfo}
                setUniversityInfo={setUniversityInfo}
                onGenerateSample={handleGenerateSample}
                selectedUniversityId={selectedUniversityId}
                onUniversityChange={handleUniversityChange}
                universityOptions={universityPresets.map(p => ({ id: p.id, name: p.name }))}
            />
          </div>

          <div className="bg-gray-800 p-6 rounded-lg shadow-lg border border-gray-700 flex flex-col items-center justify-start">
              <h2 className="text-2xl font-bold mb-4 text-center">Receipt Preview</h2>
              <div className="overflow-auto max-h-[calc(100vh-250px)] w-full p-2 bg-gray-700/50 rounded-md">
                 <ReceiptPreview 
                    ref={receiptRef} 
                    data={receiptData} 
                    universityInfo={universityInfo} 
                    currency={activePreset.currency}
                    locale={activePreset.locale}
                 />
              </div>
              <div className="mt-6 flex justify-center items-center gap-4 flex-wrap">
                <button
                  onClick={handleVerify}
                  disabled={isVerifying}
                  className="flex items-center gap-2 bg-gradient-to-r from-purple-500 to-indigo-600 hover:from-purple-600 hover:to-indigo-700 text-white font-bold py-2 px-4 rounded-lg transition-all transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    {isVerifying ? <LoaderIcon className="w-5 h-5 animate-spin" /> : <SparklesIcon className="w-5 h-5" />}
                    Verify with AI
                </button>
                <button
                  onClick={() => handleDownload('png')}
                  className="flex items-center gap-2 bg-green-600 hover:bg-green-700 text-white font-bold py-2 px-4 rounded-lg transition-transform transform hover:scale-105"
                >
                  <DownloadIcon className="w-5 h-5" />
                  Download PNG
                </button>
                <button
                  onClick={() => handleDownload('pdf')}
                  className="flex items-center gap-2 bg-red-600 hover:bg-red-700 text-white font-bold py-2 px-4 rounded-lg transition-transform transform hover:scale-105"
                >
                  <DownloadIcon className="w-5 h-5" />
                  Download PDF
                </button>
              </div>
              <div className="mt-6 w-full max-w-2xl mx-auto">
                <VerificationResults result={verificationResult} error={verificationError} />
              </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import type { VerificationResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

const verificationSchema = {
    type: Type.OBJECT,
    properties: {
        studentNameCheck: {
            type: Type.OBJECT,
            properties: {
                verified: { type: Type.BOOLEAN },
                feedback: { type: Type.STRING },
            },
            required: ['verified', 'feedback'],
        },
        universityInfoCheck: {
            type: Type.OBJECT,
            properties: {
                verified: { type: Type.BOOLEAN },
                feedback: { type: Type.STRING },
            },
            required: ['verified', 'feedback'],
        },
        dateCheck: {
            type: Type.OBJECT,
            properties: {
                verified: { type: Type.BOOLEAN },
                feedback: { type: Type.STRING },
            },
            required: ['verified', 'feedback'],
        },
    },
};


export const verifyReceipt = async (imageBase64: string): Promise<VerificationResult> => {
    const today = new Date().toLocaleDateString('en-CA'); // YYYY-MM-DD format

    const prompt = `Analyze this university tuition fee receipt. Verify these conditions and respond in JSON format according to the provided schema.
1.  **Student Name**: Is a plausible full name for a student present?
2.  **University Info**: Is a university/college name or logo clearly visible?
3.  **Valid Date**: Is there a date on the receipt (e.g., receipt date, due date) that is within the current academic year or no more than 90 days from today's date (${today})?

For each condition, provide a 'verified' boolean and brief 'feedback' text explaining your reasoning.`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: {
                parts: [
                    {
                        inlineData: {
                            mimeType: "image/jpeg",
                            data: imageBase64,
                        },
                    },
                    { text: prompt },
                ],
            },
            config: {
                responseMimeType: "application/json",
                responseSchema: verificationSchema,
            },
        });

        const jsonText = response.text.trim();
        return JSON.parse(jsonText) as VerificationResult;

    } catch (error) {
        console.error("Error calling Gemini API:", error);
        throw new Error("Failed to get verification from AI service.");
    }
};

